#include<bits/stdc++.h>
using namespace std;
long long dis[100010],a[100010];
bool vis[100010];
vector<pair<long long,long long>> mp[100010],mp1[100010];
void dijkstra(long long x)
{
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    dis[x]=0;
    priority_queue<pair<long long,long long>> q;
    q.push(make_pair(0,x));
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=true;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        long long n,m,k;
        scanf("%lld%lld%lld",&n,&m,&k);
        for(long long i=1;i<=n;i++)
        {
            mp1[i].clear();
        }
        for(long long i=1;i<=m;i++)
        {
            long long u,v,w;
            scanf("%lld%lld%lld",&u,&v,&w);
            mp1[u].push_back(make_pair(v,w));
        }
        for(long long i=1;i<=k;i++)
        {
            scanf("%lld",&a[i]);
        }
        long long base=1,ans=LLONG_MAX;
        while(base<=n)
        {
            for(long long i=1;i<=n;i++)
            {
                mp[i].clear();
                for(auto j:mp1[i])
                {
                    mp[i].push_back(j);
                }
            }
            mp[0].clear();
            mp[n+1].clear();
            for(int i=1;i<=k;i++)
            {
                if(a[i]&base)
                {
                    mp[0].push_back(make_pair(a[i],0));
                }
                else
                {
                    mp[a[i]].push_back(make_pair(n+1,0));
                }
            }
            dijkstra(0);
            ans=min(ans,dis[n+1]);
            for(long long i=1;i<=n;i++)
            {
                mp[i].clear();
                for(auto j:mp1[i])
                {
                    mp[i].push_back(j);
                }
            }
            mp[0].clear();
            mp[n+1].clear();
            for(int i=1;i<=k;i++)
            {
                if(a[i]&base)
                {
                    mp[a[i]].push_back(make_pair(n+1,0));
                }
                else
                {
                    mp[0].push_back(make_pair(a[i],0));
                }
            }
            dijkstra(0);
            ans=min(ans,dis[n+1]);
            base*=2;
        }
        printf("%lld\n",ans);
    }
    return 0;
}
